import React, { useCallback, useState } from "react";
import { CalendarDays, ExternalLink } from "lucide-react";
import { Link } from "react-router-dom";

import AmountDisplay from "@/components/primitives/AmountDisplay";
import Avatar from "@/components/primitives/Avatar";
import CopyButton from "@/components/primitives/CopyButton";
import CreditBadge from "@/components/creator/CreditBadge";
import XHandleLink from "./XHandleLink";
import { useWalletStore } from "@/state/walletStore";
import { stellarExpertAccountUrl, truncateAddress } from "@/utils/format";
import type { Profile } from "@/types/contract";

const statLabel =
  "text-[11px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted";

const identityStripTile =
  "bg-zap-bg/40 transition-colors hover:bg-zap-bg-alt/60 dark:bg-zap-bg/20";

interface ProfileHeroSummaryProps {
  profile: Profile;
}

/**
 * Identity band: 1/4 column — Avatar + CreditBadge (matches public Zap page treatment).
 * Stat strip: four equal columns aligned under the grid above.
 */
const ProfileHeroSummary: React.FC<ProfileHeroSummaryProps> = ({ profile }) => {
  const network = useWalletStore((s) => s.network);
  const [addrCopied, setAddrCopied] = useState(false);

  const copyOwner = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(profile.owner);
      setAddrCopied(true);
      window.setTimeout(() => setAddrCopied(false), 2000);
    } catch {
      /* ignore */
    }
  }, [profile.owner]);

  const registeredDate = new Date(profile.registeredAt * 1000).toLocaleDateString(
    undefined,
    { month: "long", year: "numeric" },
  );

  const explorerAccount = stellarExpertAccountUrl(profile.owner, network);

  return (
    <div className="overflow-hidden rounded-3xl border border-zap-border bg-zap-surface shadow-none">
      <div className="grid grid-cols-1 md:grid-cols-4">
        {/* 1/4 — Avatar + CreditBadge (same building blocks as ZapPage creator header) */}
        <div
          className={`${identityStripTile} flex h-full min-h-0 flex-col items-center justify-center border-b border-zap-border p-8 text-center md:border-b-0 md:border-r md:border-zap-border`}
        >
          <Avatar
            src={profile.imageUrl}
            alt={profile.displayName}
            size="xl"
            address={profile.owner}
            fallback={profile.displayName}
          />
          <div className="mt-6 flex w-full justify-center">
            <CreditBadge score={profile.creditScore} showScore clickable />
          </div>
        </div>

        {/* 3/4 — joined + identity + bio */}
        <div className={`${identityStripTile} space-y-4 p-5 md:col-span-3`}>
          <div className="flex justify-end">
            <div className="inline-flex h-fit w-fit shrink-0 items-center gap-2 rounded-full border border-zap-border bg-zap-bg px-3 py-1.5 text-[11px] font-semibold uppercase tracking-[0.08em] text-zap-ink-muted">
              <CalendarDays size={14} className="opacity-80" aria-hidden />
              Joined {registeredDate}
            </div>
          </div>

          <div className="min-w-0 space-y-4">
            <div>
              <h2 className="font-body text-2xl font-semibold leading-tight tracking-tight text-zap-ink md:text-3xl">
                {profile.displayName}
              </h2>
              <div className="mt-1 flex flex-wrap items-center gap-2">
                <span className="text-lg font-medium text-zap-ink-muted">
                  @{profile.username}
                </span>
                <CopyButton
                  text={profile.username}
                  className="h-8 w-8 !p-0 text-zap-ink-muted hover:text-zap-ink"
                />
              </div>

              <div className="mt-3 flex flex-wrap items-center gap-x-3 gap-y-2">
                <button
                  type="button"
                  onClick={copyOwner}
                  title="Click to copy Stellar address"
                  className="font-mono-chain inline-flex cursor-pointer items-center rounded-xl border border-zap-border bg-zap-bg-alt px-2 py-0.5 text-sm text-zap-ink-muted transition-opacity hover:opacity-90 dark:bg-zinc-900/60"
                >
                  {addrCopied ? "Copied" : truncateAddress(profile.owner, 4)}
                </button>
                <Link
                  to={`/@${profile.username}`}
                  className="text-sm font-semibold text-zap-brand underline decoration-zap-brand/40 underline-offset-2 transition-opacity hover:opacity-85"
                >
                  Public page — tips, unlocks, pay-to-ask
                </Link>
                <a
                  href={explorerAccount}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-1 text-sm font-semibold text-zap-brand underline decoration-zap-brand/40 underline-offset-2 transition-opacity hover:opacity-85"
                >
                  View on Explorer
                  <ExternalLink className="h-3.5 w-3.5 shrink-0 opacity-80" aria-hidden />
                </a>
              </div>
            </div>

            <p className="text-base font-medium leading-relaxed text-zap-ink">
              {profile.bio?.trim() || "No bio yet — add one from Edit profile."}
            </p>

            <div className="flex flex-wrap items-center gap-4 pt-1">
              <XHandleLink handle={profile.xHandle} followers={profile.xFollowers} />
            </div>
          </div>
        </div>
      </div>

      <p className="border-t border-zap-border bg-zap-bg-alt/40 px-5 py-3 font-body text-[11px] leading-relaxed text-zap-ink-muted dark:bg-zap-bg/30">
        The numbers below are <span className="font-semibold text-zap-ink">only for you</span>. Your
        public zap page shows credit score and X followers — not totals or tip count.
        <span className="mt-1 block">
          Unlock purchases through Zap402 increase the same on-chain totals as zaps; withdraw from
          TERMINAL when you want USDC in your wallet.
        </span>
      </p>

      <div className="grid grid-cols-2 border-t border-zap-border bg-zap-bg/40 dark:bg-zap-bg/20 md:grid-cols-4">
        <div className="border-b border-zap-border p-5 transition-colors hover:bg-zap-bg-alt/60 md:border-b-0 md:border-r">
          <p className={statLabel}>Total earned</p>
          <AmountDisplay
            amount={profile.totalTipsReceived}
            className="mt-2 block font-body text-3xl font-semibold md:text-5xl"
          />
          <p className="mt-1 font-body text-[10px] text-zap-ink-faint">Tips, zaps &amp; unlocks</p>
        </div>
        <div className="border-b border-zap-border p-5 transition-colors hover:bg-zap-bg-alt/60 md:border-b-0 md:border-r md:border-zap-border">
          <p className={statLabel}>Tip count</p>
          <p className="mt-2 font-body text-4xl font-semibold tabular-nums text-zap-ink md:text-5xl">
            {profile.totalTipsCount}
          </p>
        </div>
        <div className="border-r border-zap-border p-5 transition-colors hover:bg-zap-bg-alt/60 md:border-r">
          <p className={statLabel}>Credit score</p>
          <p className="mt-2 font-body text-4xl font-semibold tabular-nums text-zap-ink md:text-5xl">
            {profile.creditScore}
          </p>
        </div>
        <div className="p-5 transition-colors hover:bg-zap-bg-alt/60">
          <p className={statLabel}>Withdrawable</p>
          <AmountDisplay
            amount={profile.balance}
            className="mt-2 block font-body text-3xl font-semibold md:text-5xl"
          />
          <p className="mt-1 font-body text-[10px] text-zap-ink-faint">Contract escrow</p>
        </div>
      </div>
    </div>
  );
};

export default ProfileHeroSummary;
