import React from "react";
import { Navigate } from "react-router-dom";

import Loader from "@/components/primitives/Loader";
import PageContainer from "@/components/layout/PageContainer";
import { PAGE_CONTAINER_LOADING_CLASS } from "@/components/layout/pageLoadingLayout";
import ProfilePage from "@/pages/ProfilePage";
import { TERMINAL_DEFAULT_PATH } from "@/constants/terminalNav";
import { useProfileStore } from "@/state/profileStore";

/**
 * `/profile` — registration wizard when not yet a creator; registered users go to the unified HOME.
 * Waits for the first profile fetch so we don’t flash the wizard before redirect.
 */
const ProfileEntryPage: React.FC = () => {
  const loading = useProfileStore((s) => s.loading);
  const isRegistered = useProfileStore((s) => s.isRegistered);

  if (isRegistered) {
    return <Navigate to={TERMINAL_DEFAULT_PATH} replace />;
  }

  if (loading) {
    return (
      <PageContainer maxWidth="editorial" className={PAGE_CONTAINER_LOADING_CLASS}>
        <Loader size="lg" text="Loading your profile…" />
      </PageContainer>
    );
  }

  return <ProfilePage />;
};

export default ProfileEntryPage;
